import json
with open('/home/edwin/.claude/projects/-home-edwin-git-phd/d6901932-39ca-43ab-9203-2a9fd30774c2.jsonl') as f:
    for line in f:
        obj = json.loads(line.strip())
        # Find tool_use content blocks in assistant messages
        if obj.get('type') == 'assistant' and 'message' in obj:
            msg = obj['message']
            if 'content' in msg:
                for block in msg['content']:
                    if block.get('type') == 'tool_use':
                        print(json.dumps({
                            'uuid': obj['uuid'],
                            'timestamp': obj['timestamp'],
                            'tool_name': block.get('name'),
                            'tool_id': block.get('id'),
                            'input_keys': list(block.get('input', {}).keys()) if isinstance(block.get('input'), dict) else 'scalar',
                        }, indent=2))
                        print('---')
