import json
with open('/home/edwin/.claude/projects/-home-edwin-git-phd/d6901932-39ca-43ab-9203-2a9fd30774c2.jsonl') as f:
    for line in f:
        obj = json.loads(line.strip())
        # Find tool results
        if obj.get('type') == 'user' and 'message' in obj:
            msg = obj['message']
            if 'content' in msg and isinstance(msg['content'], list):
                for block in msg['content']:
                    if block.get('type') == 'tool_result':
                        content_preview = str(block.get('content', ''))[:200]
