[Find unpaired tool calls]
$ python3 -c "
import json

# Check what the 7 unpaired tool calls are
with open('/home/edwin/.claude/projects/-home-edwin-git-phd/d6901932-39ca-43ab-9203-2a9fd30774c2.jsonl') as f:
    entries = [json.loads(l.strip()) for l in f if l.strip()]

# Collect all tool_use IDs and tool_result IDs
tool_calls = {}
tool_results = set()

for e in entries:
    if e.get('type') == 'assistant' and 'message' in e:
        for b in e['message'].get('content', []):
            if b.get('type') == 'tool_use':
                tool_calls[b['id']] = b['name']
    if e.get('type') == 'user' and 'message' in e:
        content = e['message'].get('content', '')
        if isinstance(content, list):
            for b in content:
                if b.get('type') == 'tool_result':
                    tool_results.add(b.get('tool_use_id', ''))

unpaired = {k: v for k, v in tool_calls.items() if k not in tool_results}
print(f'Total tool_use blocks: {len(tool_calls)}')
print(f'Total tool_result blocks: {len(tool_results)}')
print(f'Unpaired tool calls (call without result in JSONL): {len(unpaired)}')
for tid, name in unpaired.items():
    print(f'  {name}: {tid[:20]}...')
"

[Diagnose tool call/result mismatch]
$ python3 -c "
# The mismatch is 36 calls vs 29 results in the CSV, but 43/43 in raw JSONL.
# This means the converter is dropping some. Let me trace why.
# Likely: the converter sees tool_use blocks across multiple assistant entries 
# that share the same message ID (streaming chunks), so it registers duplicates

import json
with open('/home/edwin/.claude/projects/-home-edwin-git-phd/d6901932-39ca-43ab-9203-2a9fd30774c2.jsonl') as f:
    entries = [json.loads(l.strip()) for l in f if l.strip()]

# Count tool_use blocks per assistant entry
call_count = 0
result_count = 0
msg_ids_with_tools = set()

for e in entries:
    if e.get('type') == 'assistant' and 'message' in e:
        for b in e['message'].get('content', []):
            if b.get('type') == 'tool_use':
                call_count += 1
                msg_ids_with_tools.add(e['message'].get('id', ''))
    if e.get('type') == 'user':
        content = e['message'].get('content', '')
        if isinstance(content, list):
            for b in content:
                if b.get('type') == 'tool_result':
                    result_count += 1

print(f'tool_use blocks in JSONL: {call_count}')
print(f'tool_result blocks in JSONL: {result_count}')
print(f'Unique message IDs with tools: {len(msg_ids_with_tools)}')
print()

# The issue: Claude Code sends streaming chunks. The same tool_use appears
# in multiple assistant entries (first as partial, then as complete).
# Let's check for duplicate tool IDs
tool_ids_seen = []
for e in entries:
    if e.get('type') == 'assistant' and 'message' in e:
        for b in e['message'].get('content', []):
            if b.get('type') == 'tool_use':
                tool_ids_seen.append(b['id'])

from collections import Counter
dupes = {k: v for k, v in Counter(tool_ids_seen).items() if v > 1}
print(f'Duplicate tool IDs (same tool_use in multiple entries): {len(dupes)}')
if dupes:
    for tid, count in list(dupes.items())[:5]:
        print(f'  {tid[:20]}... appears {count} times')
"
